namespace BgCommon.Script.Runtime.Models;/// <summary>/// 引用的程序集信息模型./// </summary>public class ReferencedAsseblyInfo : ObservableObject{    private string name = string.Empty;    private string fullName = string.Empty;    private string displayName = string.Empty;    private string info = string.Empty;    private bool isReferenced;    private bool isSystemAssembly;    private bool isGlobalAssembly;    private bool allowRemove;    /// <summary>    /// Initializes a new instance of the <see cref="ReferencedAsseblyInfo"/> class.    /// </summary>    public ReferencedAsseblyInfo()    {    }    /// <summary>    /// Gets or sets 程序集名称.    /// </summary>    public string Name    {        get => this.name;        set => this.SetProperty(ref this.name, value);    }    /// <summary>    /// Gets or sets 程序集全名.    /// </summary>    public string FullName    {        get => this.fullName;        set => this.SetProperty(ref this.fullName, value);    }    /// <summary>    /// Gets or sets 显示名称.    /// </summary>    public string DisplayName    {        get => this.displayName;        set => this.SetProperty(ref this.displayName, value);    }    /// <summary>    /// Gets or sets 详细信息描述.    /// </summary>    public string Info    {        get => this.info;        set => this.SetProperty(ref this.info, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否已被引用.    /// </summary>    public bool IsReferenced    {        get => this.isReferenced;        set => this.SetProperty(ref this.isReferenced, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否为全局程序集.    /// </summary>    public bool IsGlobalAssembly    {        get => this.isGlobalAssembly;        set => this.SetProperty(ref this.isGlobalAssembly, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否为系统程序集.    /// </summary>    public bool IsSystemAssembly    {        get => this.isSystemAssembly;        set => this.SetProperty(ref this.isSystemAssembly, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否允许移除.    /// </summary>    public bool AllowRemove    {        get => this.allowRemove;        set => this.SetProperty(ref this.allowRemove, value);    }}